import React, { useState, useEffect } from "react";
import NoteCard from "../Notes/NoteCard"; // Ensure this path is correct
import NoteModal from "../Notes/NoteModel"; // Ensure this path is correct

// Key for localStorage
const LOCAL_STORAGE_KEY = 'react-simple-notes-app';

const NotesPage = () => {
  const [notes, setNotes] = useState([]);
  const [selectedNote, setSelectedNote] = useState(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [loading, setLoading] = useState(true);

  // 1. Initial Load: Fetch notes from localStorage
  useEffect(() => {
    try {
      const storedNotes = localStorage.getItem(LOCAL_STORAGE_KEY);
      if (storedNotes) {
        setNotes(JSON.parse(storedNotes));
      }
    } catch (error) {
      console.error("Failed to load notes from local storage:", error);
    } finally {
      setLoading(false);
    }
  }, []); // Run only once on mount

  // 2. Data Persistence: Save notes to localStorage whenever the 'notes' state changes
  useEffect(() => {
    if (!loading) { // Only save after initial loading is done
      try {
        localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(notes));
      } catch (error) {
        console.error("Failed to save notes to local storage:", error);
      }
    }
  }, [notes, loading]);

  // --- Modal Handlers ---

  const handleOpenModal = (note = null) => { // Default to null for new note
    setSelectedNote(note);
    setIsModalOpen(true);
  };

  const handleCloseModal = () => {
    setIsModalOpen(false);
    setSelectedNote(null);
  };

  // --- CRUD Operations ---

  const handleSaveNote = (noteToSave) => {
    if (noteToSave.id) {
      // Logic for EDITING an existing note
      setNotes(prevNotes => 
        prevNotes.map(note => 
          note.id === noteToSave.id ? noteToSave : note
        )
      );
    } else {
      // Logic for CREATING a NEW note
      const newNote = {
        ...noteToSave,
        id: Date.now(), // Simple unique ID generation (use UUID in production)
        createdAt: new Date().toISOString(),
      };
      setNotes(prevNotes => [newNote, ...prevNotes]); // Add new note to the beginning
    }
    handleCloseModal();
  };

  const handleDeleteNote = (id) => {
    // Logic for DELETING a note
    if (window.confirm("Are you sure you want to delete this note?")) {
      setNotes(prevNotes => prevNotes.filter(note => note.id !== id));
      handleCloseModal();
    }
  };

  // --- Render ---

  if (loading) {
    return (
      <div className="flex justify-center items-center h-screen text-xl text-gray-600">
        Loading notes...
      </div>
    );
  }

  return (
    <div className="container mx-auto p-4 min-h-screen relative">
      <h1 className="text-4xl font-extrabold text-center mb-10 text-gray-800">
        📝 My Notes
      </h1>

      {notes.length === 0 ? (
        <div className="text-center mt-20 p-8 border-2 border-dashed border-gray-300 rounded-xl max-w-lg mx-auto bg-white shadow-sm">
          <p className="text-xl text-gray-600 mb-4">
            You don't have any notes yet!
          </p>
          <button 
            onClick={() => handleOpenModal(null)}
            className="bg-indigo-600 text-white py-3 px-6 rounded-lg font-semibold hover:bg-indigo-700 transition-colors duration-200 shadow-md"
          >
            Create Your First Note
          </button>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
          {notes.map((note) => (
            <NoteCard key={note.id} note={note} onOpenModal={handleOpenModal} />
          ))}
        </div>
      )}

      {/* Floating Action Button (FAB) for New Note */}
      <button 
        onClick={() => handleOpenModal(null)}
        className="fixed bottom-8 right-8 bg-indigo-600 text-white p-5 rounded-full shadow-2xl hover:bg-indigo-700 transition-transform duration-200 transform hover:scale-110 z-30"
        title="Add New Note"
      >
        <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
        </svg>
      </button>

      {/* Note Modal */}
      <NoteModal
        note={selectedNote}
        isOpen={isModalOpen}
        onClose={handleCloseModal}
        onSave={handleSaveNote}
        onDelete={handleDeleteNote} // Pass the new delete handler
      />
    </div>
  );
};

export default NotesPage;
